"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[5510],{40781(e,n,i){i.r(n),i.d(n,{assets:()=>d,contentTitle:()=>u,default:()=>c,frontMatter:()=>a,metadata:()=>r,toc:()=>h});const r=JSON.parse('{"id":"learning/courses/quantum-computing-in-practice/running-quantum-circuits","title":"Quantencircuits ausf\xfchren","description":"Ein \xdcberblick \xfcber die Grundlagen der Durchf\xfchrung einer Quantenberechnung im Utility-Ma\xdfstab.","source":"@site/i18n/de/docusaurus-plugin-content-docs/current/learning/courses/quantum-computing-in-practice/running-quantum-circuits.mdx","sourceDirName":"learning/courses/quantum-computing-in-practice","slug":"/learning/courses/quantum-computing-in-practice/running-quantum-circuits","permalink":"/learning/courses/quantum-computing-in-practice/running-quantum-circuits","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-computing-in-practice/running-quantum-circuits.mdx","tags":[],"version":"current","frontMatter":{"title":"Quantencircuits ausf\xfchren","sidebar_label":"Quantencircuits ausf\xfchren","description":"Ein \xdcberblick \xfcber die Grundlagen der Durchf\xfchrung einer Quantenberechnung im Utility-Ma\xdfstab.","notebook_path":"learning/courses/quantum-computing-in-practice/running-quantum-circuits.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"Einleitung","permalink":"/learning/courses/quantum-computing-in-practice/introduction"},"next":{"title":"Utility-Scale QAOA","permalink":"/learning/courses/quantum-computing-in-practice/utility-scale-qaoa"}}');var s=i(74848),t=i(28453);const a={title:"Quantencircuits ausf\xfchren",sidebar_label:"Quantencircuits ausf\xfchren",description:"Ein \xdcberblick \xfcber die Grundlagen der Durchf\xfchrung einer Quantenberechnung im Utility-Ma\xdfstab.",notebook_path:"learning/courses/quantum-computing-in-practice/running-quantum-circuits.ipynb"},u=void 0,d={},h=[{value:"\xdcberblick \xfcber die Lektion",id:"lesson-overview",level:2},{value:"Hardware \u2013 IBM-Quantenprozessoren",id:"hardware-ibm-quantum-processors",level:2},{value:"Software: Qiskit und Qiskit Runtime",id:"software-qiskit-and-qiskit-runtime",level:2},{value:"Quantencircuits",id:"quantum-circuits",level:2},{value:"Entwurf eines Quantencircuits: Qiskit Patterns",id:"designing-a-quantum-circuit-qiskit-patterns",level:2},{value:"Abbilden (Map)",id:"map",level:3},{value:"Optimieren (Optimize)",id:"optimize",level:3},{value:"Qiskit Transpiler",id:"qiskit-transpiler",level:4},{value:"Error Suppression",id:"error-suppression",level:4},{value:"Ausf\xfchren (Execute)",id:"execute",level:3},{value:"Nachverarbeiten (Post-process)",id:"post-process",level:3},{value:"Fazit",id:"conclusion",level:2}];function l(e){const n={a:"a",code:"code",em:"em",h2:"h2",h3:"h3",h4:"h4",img:"img",li:"li",ol:"ol",p:"p",strong:"strong",ul:"ul",...(0,t.R)(),...e.components},{IBMVideo:r}=n;return r||function(e,n){throw new Error("Expected "+(n?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("IBMVideo",!0),(0,s.jsxs)(s.Fragment,{children:["\n",(0,s.jsxs)(n.p,{children:["Schau dir das Video \xfcber Quantencircuits und Primitives von Olivia Lanes an, oder \xf6ffne es in einem separaten Fenster auf ",(0,s.jsx)(n.a,{href:"https://youtube.com/watch?v=NTplT4WnNbk",children:"YouTube."})]}),"\n",(0,s.jsx)(r,{id:"134063416",title:"In diesem Video erkl\xe4rt Olivia Lanes Quantencircuits und Primitives. Sie behandelt die Qiskit Runtime Primitives Estimator und Sampler."}),"\n",(0,s.jsx)(n.h2,{id:"lesson-overview",children:"\xdcberblick \xfcber die Lektion"}),"\n",(0,s.jsx)(n.p,{children:"Diese Lektion bietet einen \xdcberblick \xfcber die Grundlagen der Durchf\xfchrung einer Quantenberechnung im Utility-Ma\xdfstab, von der verwendeten Quantenhardware bis hin zu den Prinzipien, die beim Entwurf eines Quantencircuits zu beachten sind. Am Ende dieser Lektion solltest du idealerweise wissen:"}),"\n",(0,s.jsxs)(n.ol,{children:["\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsx)(n.p,{children:"Was IBM\xae-Quantencomputer tats\xe4chlich sind. Du musst die Grundlagen der Hardware-Eigenschaften kennen, um deine Quantencircuits optimal f\xfcr die Ausf\xfchrung darauf zu gestalten."}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsx)(n.p,{children:"Was Qiskit ist, was Primitives sind und wie wir sie nutzen k\xf6nnen, um Quantencircuits zu erstellen und auszuf\xfchren."}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsx)(n.p,{children:"Der typische Workflow, den wir bei der Durchf\xfchrung von Experimenten im gro\xdfen Ma\xdfstab verfolgen. Dazu geh\xf6ren die Auswahl der besten Primitives f\xfcr deinen Anwendungsfall, die Abbildung eines Problems auf einen Quantencircuit sowie die Anwendung von Error Mitigation und Error Suppression, die es uns erm\xf6glichen, das Maximum aus diesen Maschinen herauszuholen."}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(n.h2,{id:"hardware-ibm-quantum-processors",children:"Hardware \u2013 IBM-Quantenprozessoren"}),"\n",(0,s.jsx)(n.p,{children:"Um zu verstehen, wie wir beim Entwurf gro\xdfer Quantencircuits optimale Entscheidungen treffen k\xf6nnen, m\xfcssen wir ein wenig \xfcber die tats\xe4chliche Hardware wissen, die diese Circuits ausf\xfchren wird. Lass uns also kurz \xfcber physische Qubits und IBM-Quantenprozessoren sprechen."}),"\n",(0,s.jsxs)(n.p,{children:["IBM-Quantenprozessoren werden mit supraleitenden Transmon-Qubits gebaut, die elektrische Schaltkreise sind, die aus einem ",(0,s.jsx)(n.em,{children:"Josephson-Kontakt"})," und einem parallel dazu geschalteten Kondensator bestehen. Der Josephson-Kontakt ist ein nichtlinearer Induktor, der aus zwei \xfcberlappenden Schichten supraleitenden Metalls mit einer isolierenden Barriere dazwischen besteht. Bei sehr niedrigen Temperaturen paaren sich die Elektronen in Supraleitern und bilden sogenannte Cooper-Paare. Cooper-Paare k\xf6nnen spontan durch die isolierende Barriere von einer Seite des Kontakts zur anderen tunneln. Dieses Tunnelverhalten erzeugt die nichtlinearen Eigenschaften, die unser Qubit ausmachen."]}),"\n",(0,s.jsxs)(n.p,{children:["Auf dem Chip werden Mikrowellen\xfcbertragungsleitungen hergestellt, um Mikrowellensignale an die Qubits zu liefern. Wenn wir hochkalibrierte Mikrowellenpulse \u2013 mit spezifischer Frequenz, Amplitude, Form und Dauer \u2013 an die Leitungen anlegen, k\xf6nnen wir die Qubits dazu bringen, bestimmte Dinge zu tun. Das bildet die Grundlage unserer Quantengates. Wir fertigen den Chip so, dass benachbarte Qubits in einer bestimmten Gitterstruktur namens Heavy-Hex-Gitter verbunden sind. Diese Konnektivit\xe4t \u2013 die sogenannte ",(0,s.jsx)(n.em,{children:"Topologie"})," \u2013 unserer Prozessoren ist ein wichtiger Faktor beim Entwurf eines Circuits, wor\xfcber wir sp\xe4ter in der Lektion sprechen werden."]}),"\n",(0,s.jsx)(n.p,{children:"Die Anweisungen f\xfcr den Mikrowellenpuls gehen von deinem Computer \xfcber die Cloud zu raumtemperatur-Kontrollelektronik, die diese Anweisungen interpretiert und die Pulse physisch erzeugt. Nachdem die Raumtemperatur-Kontrollboxen die Pulse erzeugt haben, wandern sie durch Kabel in einen Verd\xfcnnungsk\xfchlschrank und schlie\xdflich zum Quantenchip. Das Signal geht in die Resonatoren, durch einen Drahtbond und flie\xdft dann die \xdcbertragungsleitung hinunter in unsere Qubits."}),"\n",(0,s.jsxs)(n.p,{children:["IBM hat Dutzende von Quantencomputern auf der ganzen Welt, und wir haben unsere Flotte k\xfcrzlich so aufger\xfcstet, dass sie ausschlie\xdflich Prozessoren mit mehr als 100 Qubits hat. Einige befinden sich in einem IBM-Quantenrechenzentrum im Norden von New York und werden \xfcber die Cloud f\xfcr alle zug\xe4nglich gemacht \u2013 und einige sind dedizierte, vor Ort befindliche Systeme, die Partner im IBM Quantum\xae Network unterst\xfctzen. Du kannst dich bei ",(0,s.jsx)(n.a,{href:"https://quantum.cloud.ibm.com",children:"quantum.cloud.ibm.com"})," anmelden, um zu sehen, auf welche Prozessoren du Zugriff hast."]}),"\n",(0,s.jsx)(n.p,{children:"Jeder Prozessor listet drei Leistungsmetriken auf, die wir in der vorherigen Lektion besprochen haben, aber zur Erinnerung: Qubit-Anzahl, EPLG und CLOPS."}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Qubit-Anzahl."})," Das ist selbsterkl\xe4rend: Es ist die Anzahl der gesamten verf\xfcgbaren Qubits auf einem einzelnen Quantenprozessor. F\xfcr ein relativ gro\xdfes Problem im Utility-Ma\xdfstab musst du sicherstellen, dass du einen Prozessor mit gen\xfcgend Qubits verwendest, um das Problem bew\xe4ltigen zu k\xf6nnen. Aber die Qubit-Anzahl allein ist nicht das einzige, was z\xe4hlt."]}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"EPLG"}),', oder \u201eerrors per layered gate" (Fehler pro geschichtetem Gate). Dies ist ein Ma\xdf f\xfcr die Qualit\xe4t der Qubits und Quantengates. Es misst den durchschnittlichen Fehler, den jedes Gate in einem Circuit einf\xfchrt, der benachbarte Qubits in einer Kette von 100 Qubits verschr\xe4nkt. Du m\xf6chtest, dass dies so klein wie m\xf6glich ist.']}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"CLOPS"}),', oder \u201ecircuit layer operations per second" (Circuit-Schichtoperationen pro Sekunde). Dies quantifiziert die Geschwindigkeit des Prozessors. Es misst, wie viele Schichten eines bestimmten Benchmark-Circuits, der als Quantum-Volume-Circuit bezeichnet wird, eine Quantum Processing Unit (QPU) pro Zeiteinheit ausf\xfchren kann. Je h\xf6her die Zahl, desto schneller k\xf6nnen wir rechnen.']}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"Die Bedeutung jeder dieser Metriken variiert je nach spezifischer Anwendung, und in zuk\xfcnftigen Lektionen werden wir uns reale Beispiele ansehen, um zu sehen, wie sich jeder dieser Faktoren auf das Ergebnis einer Berechnung auswirken kann."}),"\n",(0,s.jsx)(n.h2,{id:"software-qiskit-and-qiskit-runtime",children:"Software: Qiskit und Qiskit Runtime"}),"\n",(0,s.jsx)(n.p,{children:"Um dein Quantenproblem in Anweisungen f\xfcr einen Quantencomputer umzuwandeln, verwendest du Qiskit, das von IBM entwickelte Open-Source-Software-Development-Kit f\xfcr die Arbeit mit Quantencomputern. Es gibt auch das Qiskit-Ecosystem \u2013 eine Sammlung von Software-Tutorials und -Funktionen, die auf den Kernfunktionalit\xe4ten von Qiskit aufbauen oder diese erweitern \u2013 und Qiskit Runtime \u2013 einen Quantencomputing-Service und ein Programmiermodell, das Nutzern erm\xf6glicht, ihre Quanten-Workloads zu gestalten und zu optimieren und sie mithilfe von Qiskit Runtime Primitives effizient auszuf\xfchren."}),"\n",(0,s.jsx)(n.p,{children:"Ein Primitive ist ein kleiner Baustein, den du verwenden kannst, um einen gr\xf6\xdferen Circuit oder Job zu entwerfen. Die beiden f\xfcr uns wichtigsten Primitives sind der Sampler und der Estimator, auf die wir gleich noch genauer eingehen werden."}),"\n",(0,s.jsxs)(n.p,{children:["Mit dem j\xfcngsten Release von Qiskit v1.0 ist Qiskit leistungsf\xe4higer und stabiler denn je geworden. F\xfcr diejenigen unter euch, die gerade erst anfangen, seid ihr zum perfekten Zeitpunkt eingestiegen! F\xfcr diejenigen, die bereits mit Qiskit vertraut sind, m\xfcsst ihr die neueste Version herunterladen und neu installieren. Eine vollst\xe4ndige Installationsanleitung findest du in der ",(0,s.jsx)(n.a,{href:"/guides/install-qiskit",children:"Anleitung zur Installation von Qiskit"}),"."]}),"\n",(0,s.jsx)(n.h2,{id:"quantum-circuits",children:"Quantencircuits"}),"\n",(0,s.jsxs)(n.p,{children:["Jetzt sind wir bereit, die Grundlage von Quantenprogrammen zu besprechen: Quantencircuits. Dieser Abschnitt dient nur als Auffrischung \u2013 wenn du nicht mit Quantencircuits vertraut bist, empfehlen wir dir, mehr dar\xfcber zu erfahren, indem du die Lektion ",(0,s.jsx)(n.a,{href:"/learning/courses/basics-of-quantum-information/quantum-circuits/introduction",children:"Quantencircuits"}),' im Kurs \u201eBasics of Quantum Information" besuchst, bevor du fortf\xe4hrst.']}),"\n",(0,s.jsx)(n.p,{children:"Ein Quantencircuit ist ein Netzwerk von Quantengates und Messungen, die durch Leitungen verbunden sind, die Qubits darstellen, wie unten gezeigt. Quantencircuits k\xf6nnen wie Notenbl\xe4tter gelesen werden, von links nach rechts, beginnend bei Zeit 0 auf der linken Seite. Virtuelle Qubits \u2013 diejenigen, die noch keinem physischen Qubit auf einem Prozessor zugewiesen wurden \u2013 sind in aufsteigender Reihenfolge von oben nach unten aufgelistet."}),"\n",(0,s.jsx)(n.p,{children:'Gates werden durch verschiedene Symbole auf den Leitungen der beteiligten Qubit(s) dargestellt. Einzelqubit-Gates \u2013 wie ein Hadamard-Gate, unten abgebildet (das K\xe4stchen mit dem H) \u2013 betreffen nur das Qubit, auf dessen Leitung es platziert ist. Mehrqubit-Gates \u2013 wie ein CNOT-Gate, ebenfalls unten gezeigt (das Pluszeichen im Kreis mit einer Linie, die mit q0 verbunden ist) \u2013 betreffen zwei oder mehr Qubits. Im dargestellten CNOT-Gate \xe4ndert sich der Zustand von q1 entsprechend dem Zustand von q0. Nachdem alle Gates ausgef\xfchrt wurden, k\xf6nnen wir die Qubits messen, angezeigt durch die schwarzen Gates mit dem Messsymbol. Die Ergebnisse der Messungen werden in klassische Register geschrieben, dem doppellinierten \u201emeas"-Bus unten.'}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.img,{alt:"Beispiel eines einfachen Quantencircuits",src:i(54776).A+"",width:"2715",height:"1424"})}),"\n",(0,s.jsx)(n.p,{children:'Eine wichtige Eigenschaft eines Circuits ist seine Tiefe. Die Tiefe eines Quantencircuits ist die minimale Anzahl von \u201eSchichten" von Quantengates, die parallel ausgef\xfchrt werden und zum Abschluss des Circuits erforderlich sind. Quantengates k\xf6nnen parallel (gleichzeitig) ausgef\xfchrt werden, solange sie keine Qubits gemeinsam haben. Aber wenn zwei oder mehr Gates auf dasselbe Qubit wirken, k\xf6nnen wir sie nicht parallel ausf\xfchren \u2013 sie m\xfcssen in zwei separaten Schichten, eine nach der anderen, ausgef\xfchrt werden.'}),"\n",(0,s.jsx)(n.p,{children:"Es gibt eine andere, weniger offensichtliche Methode, die Tiefe eines Circuits zu bestimmen, indem man eine Art Spiel spielt. Die Regeln sind einfach: Ausgehend von einer beliebigen Qubit-Leitung auf der linken Seite muss man nach rechts reisen und die Anzahl der Gates z\xe4hlen, denen man auf seinem Weg begegnet. Man darf zu einer benachbarten Leitung springen, nur wenn sie durch ein Mehrqubit-Gate mit der aktuellen Leitung verbunden ist. Das Ziel ist, die Anzahl der angetroffenen Gates auf dem Weg zu maximieren. Diese maximale Zahl ist auch die Tiefe des Circuits."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.img,{alt:"Beispiel eines Circuits mit neun Schichten",src:i(77815).A+"",width:"3840",height:"1893"})}),"\n",(0,s.jsx)(n.p,{children:"Da die Implementierung von Quantengates Zeit in Anspruch nimmt, entspricht die Tiefe eines Circuits in etwa der Zeit, die ein Quantencomputer f\xfcr die Ausf\xfchrung des Circuits ben\xf6tigt. Einige Maschinen sind aufgrund der Dekoh\xe4renzzeiten der Qubits auf dem Prozessor besser f\xfcr gro\xdfe Tiefencircuits geeignet als andere. Daher m\xfcssen wir die Tiefe eines Circuits kennen, um zu wissen, ob er auf einem bestimmten Ger\xe4t ausgef\xfchrt werden kann."}),"\n",(0,s.jsx)(n.h2,{id:"designing-a-quantum-circuit-qiskit-patterns",children:"Entwurf eines Quantencircuits: Qiskit Patterns"}),"\n",(0,s.jsx)(n.p,{children:"Wie gehen wir also beim Entwurf und der Ausf\xfchrung eines Quantencircuits vor? Der einfachste Weg, einen typischen Quantencomputing-Workflow zu verstehen, sind Qiskit Patterns. Qiskit Patterns sind ein konzeptionelles Framework, das Nutzern erm\xf6glicht, Quanten-Workloads durch die Implementierung bestimmter Schritte mit modularen Tools auszuf\xfchren. Dies erm\xf6glicht die Durchf\xfchrung von Quantencomputing-Aufgaben durch eine leistungsstarke heterogene (CPU/GPU/QPU)-Computing-Infrastruktur. Die Schritte k\xf6nnen als Service durchgef\xfchrt werden und k\xf6nnen Ressourcenmanagement beinhalten, das eine nahtlose Zusammensetzbarkeit neuer Funktionen erm\xf6glicht, sobald sie entwickelt werden."}),"\n",(0,s.jsx)(n.p,{children:"Hier sind die Hauptschritte, die erfahrene Qiskit-Nutzer wahrscheinlich kennen werden."}),"\n",(0,s.jsxs)(n.ol,{children:["\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Abbilden (Map)."})," In diesem Schritt formalisieren wir, wie wir ein allgemeines Problem, das uns interessiert, nehmen und herausfinden, wie wir es in Form eines Quantencircuits auf einen Quantencomputer abbilden k\xf6nnen."]}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Optimieren (Optimize)."})," In diesem Schritt verwenden wir den Qiskit Transpiler, um den Circuit auf einer tats\xe4chlichen physischen Qubit-Hardware zu routen und zu platzieren. Dies beinhaltet die \xdcbersetzung der einzelnen Quantengates in Sequenzen von Operationen, die auf der Hardware ausgef\xfchrt werden, sowie eine Optimierung der Gate-Platzierung."]}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Ausf\xfchren (Execute)."})," Qiskit Runtime Primitives stellen die Schnittstelle zu IBM-Quantum-Hardware bereit, die es erm\xf6glicht, transpilierte Circuits auszuf\xfchren. Dieser Schritt umfasst auch Error Suppression- und Mitigation-Techniken, die weitgehend vom Nutzer abstrahiert werden k\xf6nnen."]}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Nachverarbeiten (Post-process)."})," In diesem Schritt werden die Daten des Quantenprozessors selbst verarbeitet und dem Nutzer n\xfctzliche Ergebnisse zum urspr\xfcnglichen Problem geliefert. Im Wesentlichen umfasst dies jede weitere Analyse der gewonnenen Daten."]}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(n.h3,{id:"map",children:"Abbilden (Map)"}),"\n",(0,s.jsx)(n.p,{children:'Der Map-Schritt stellt im Wesentlichen die Frage: \u201eWie \xfcbersetze ich mein Problem in einen Quantencircuit, der vern\xfcnftigerweise auf Quantenhardware ausgef\xfchrt werden kann?" Es steht au\xdfer Frage: Das Abbilden ist ein schwieriges Problem und ein aktives Forschungsgebiet. Es gibt keine narrensichere Methode, die Erfolg garantiert, aber es gibt empfohlene Richtlinien und Beispiele f\xfcr Probleme, die wir bereits wissen, wie man sie abbildet.'}),"\n",(0,s.jsx)(n.p,{children:"Die erste Richtlinie lautet: Lass klassische Computer alles tun, was sie besser k\xf6nnen. Aufgaben, die f\xfcr klassische Computer einfach sind, werden wahrscheinlich nicht von einem Quantencomputer profitieren. Quantencomputer sind f\xfcr Probleme, die klassisch schwer sind. Wenn du nat\xfcrlich zum allerersten Mal Qiskit oder einen Quantencomputer verwendest, mach dir keine Sorgen um ein rechnerisch komplexes Problem. Teile es in kleinere, handhabbare Probleme auf, die du l\xf6sen kannst, bevor du direkt auf ein Projekt im Utility-Ma\xdfstab zielst."}),"\n",(0,s.jsx)(n.p,{children:"Als n\xe4chstes \xfcbersetze die Ergebnisse f\xfcr dein Problem, die du messen oder verstehen m\xf6chtest, in einen Erwartungswert oder eine Kostenfunktion. Eine Kostenfunktion ist eine problemspezifische Funktion, die das Ziel des Problems als etwas Zu-Minimierendes oder Zu-Maximierendes definiert. Sie kann verwendet werden, um zu sehen, wie gut ein Testzustand oder eine L\xf6sung in Bezug auf dieses Ziel abschneidet. Dieses Konzept kann auf verschiedene Anwendungen in der Chemie, im maschinellen Lernen, im Finanzwesen, in der Optimierung usw. angewendet werden \u2013 es spielt keine Rolle, aus welchem Fachgebiet du das Problem angehst."}),"\n",(0,s.jsx)(n.p,{children:"Beachte auch, dass die Hardware, die du verwenden wirst, eine spezifische Topologie hat, wie wir im Hardware-Abschnitt besprochen haben. Einige Qubits sind verbunden, andere nicht \u2013 du musst dein Problem auf einen Circuit abbilden, der die Heavy-Hex-Topologie der IBM-Quantenprozessoren respektiert."}),"\n",(0,s.jsx)(n.p,{children:"F\xfcr jetzt ist das Wichtigste, das du im Hinterkopf behalten solltest, dass diese Phase \xdcbung erfordert. Du musst nicht nur dein Problem, sondern auch die Hardware-F\xe4higkeiten gut verstehen \u2013 und wir werden in zuk\xfcnftigen Lektionen konkrete Beispiele und Anwendungsf\xe4lle durchgehen, um zu sehen, wie all diese \xdcberlegungen ausbalanciert werden k\xf6nnen."}),"\n",(0,s.jsx)(n.h3,{id:"optimize",children:"Optimieren (Optimize)"}),"\n",(0,s.jsx)(n.p,{children:"Als n\xe4chstes m\xfcssen wir einen Quantenprozessor ausw\xe4hlen, der genug Qubits in ausreichend hoher Qualit\xe4t hat, dass wir unseren Quantencircuit ausf\xfchren k\xf6nnen. Treffe diese Entscheidungen anhand der drei Metriken, die wir im Hardware-Abschnitt besprochen haben: Qubit-Anzahl, EPLG und CLOPS."}),"\n",(0,s.jsx)(n.p,{children:"Dann optimieren wir unseren Circuit f\xfcr die ausgew\xe4hlte Hardware. Zun\xe4chst m\xfcssen wir unseren Circuit effizient platzieren und routen. Layout bezeichnet die Abbildung der virtuellen Qubits im Circuit auf die physischen Qubits auf dem Prozessor. Routing bezeichnet die Anpassung des Circuits, damit die Konnektivit\xe4t zwischen virtuellen Qubits im Circuit mit der Konnektivit\xe4t der physischen Qubits auf dem Prozessor \xfcbereinstimmt. Es gibt ein paar Dinge, die man beim Layout- und Routing-Schritt beachten sollte."}),"\n",(0,s.jsxs)(n.ol,{children:["\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsx)(n.p,{children:"Nicht alle Qubits sind verbunden. Einige befinden sich auf dem Chip sehr weit voneinander entfernt, und wir m\xfcssen Fernwechselwirkungen wo immer m\xf6glich reduzieren oder eliminieren. Du k\xf6nntest eine Sequenz von SWAP-Gates zwischen benachbarten Qubits anwenden, um die Qubit-Informationen zu verschieben, aber SWAP-Gates sind kostspielig und fehleranf\xe4llig, daher gibt es m\xf6glicherweise bessere Wege. Versuche, zu viele kostspielige SWAP-Gates zu vermeiden."}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:["Layout und Routing sind iterative Prozesse. Du kannst es von Hand machen, aber es gibt auch ein Qiskit-Tool namens ",(0,s.jsx)(n.code,{children:"mapomatic"}),", das Empfehlungen f\xfcr ein physisches Qubit-Layout basierend auf ungef\xe4hren Fehlerraten geben kann. Der Transpiler (den wir gleich besprechen werden) kann auch einen fundierten Vorschlag machen."]}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"Als n\xe4chstes k\xf6nnen wir Sequenzen von Einzelqubit-Gates, die auf dasselbe Qubit wirken, zu einzelnen Gates zusammensetzen \u2013 und wir k\xf6nnen manchmal auch unn\xf6tige Gates oder Kombinationen von Gates loswerden. Einige Kombinationen von Gates k\xf6nnen beispielsweise auf einfachere Kombinationen reduziert werden \u2013 und manchmal entspricht eine Kombination von Gates der Identit\xe4tsoperation, sodass wir sie einfach eliminieren k\xf6nnen. Du kannst dies automatisch mit dem Qiskit Transpiler tun \u2013 aber du kannst es auch manuell Gate f\xfcr Gate machen, wenn du mehr Kontrolle m\xf6chtest."}),"\n",(0,s.jsx)(n.p,{children:"Sobald wir das Circuit-Layout, Routing und die Gate-Anzahl verbessert haben \u2013 entweder von Hand oder mit dem Transpiler \u2013, m\xf6chten wir unseren Circuit normalerweise visualisieren, um sicherzustellen, dass das Timing aller Gates Sinn ergibt. Es gibt ein Argument, das du im Transpiler setzen kannst, um den Zeitplan deines Circuits zu visualisieren und sicherzustellen, dass alles so ausgerichtet ist, wie du es erwarten w\xfcrdest."}),"\n",(0,s.jsx)(n.h4,{id:"qiskit-transpiler",children:"Qiskit Transpiler"}),"\n",(0,s.jsx)(n.p,{children:"Wie bereits erw\xe4hnt, kann der Qiskit Transpiler in den fr\xfchen Phasen des Patterns-Workflows helfen. Nun wollen wir uns seine F\xe4higkeiten genauer ansehen. Er kann einen gegebenen Eingangs-Circuit neu schreiben, damit er der Topologie eines bestimmten Quantenger\xe4ts entspricht, und den Circuit f\xfcr die Ausf\xfchrung und die Widerstandsf\xe4higkeit gegen Rauschen optimieren. Au\xdferdem schreibt er einen gegebenen Circuit in die Basisgates des spezifischen Quantenprozessors um, den du ausgew\xe4hlt hast."}),"\n",(0,s.jsx)(n.p,{children:"Qiskit hat vier eingebaute Transpilierungs-Pipelines, die verschiedenen Optimierungsebenen entsprechen, und sofern du nicht bereits mit Quantencircuit-Optimierung vertraut bist, empfehlen wir dir, eine davon zu verwenden. Standardm\xe4\xdfig umfasst der Transpilierungsprozess diese sechs Schritte:"}),"\n",(0,s.jsxs)(n.ol,{children:["\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsx)(n.p,{children:"Initialisierung. Diese Phase f\xfchrt alle anf\xe4nglichen Durchl\xe4ufe aus, die erforderlich sind, bevor wir damit beginnen, den Circuit auf dem Backend einzubetten. Dies umfasst typischerweise das Entfalten benutzerdefinierter Anweisungen und die Konvertierung des Circuits in Einzel- und Zwei-Qubit-Gates."}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:["Layout. Diese Phase bildet die virtuellen Qubits im Circuit auf die physischen Qubits eines Backends ab. Weitere Details findest du unter ",(0,s.jsx)(n.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler#layout-stage",children:"Layout Stage"}),"."]}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:["Routing. Diese Phase wird nach dem Anwenden eines Layouts ausgef\xfchrt und f\xfcgt Gates (wie Swap-Gates) in den urspr\xfcnglichen Circuit ein, um ihn mit der Konnektivit\xe4t des Backends kompatibel zu machen. Weitere Details findest du unter ",(0,s.jsx)(n.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler#routing-stage",children:"Routing Stage"}),"."]}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsxs)(n.p,{children:["\xdcbersetzung. Diese Phase \xfcbersetzt die Gates im Circuit in den Basissatz des Ziel-Backends. Weitere Details findest du unter ",(0,s.jsx)(n.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler#translation-stage",children:"Translation Stage"}),"."]}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsx)(n.p,{children:"Optimierung. Diese Phase f\xfchrt die Haupt-Optimierungsschleife wiederholt aus, bis eine Bedingung (wie das Erreichen einer bestimmten Zieltiefe) erf\xfcllt ist. Wir haben vier verschiedene Optimierungsebenen zur Auswahl, die unten beschrieben sind."}),"\n"]}),"\n",(0,s.jsxs)(n.li,{children:["\n",(0,s.jsx)(n.p,{children:"Scheduling. Diese Phase ist f\xfcr hardware-bewusste Scheduling-Durchl\xe4ufe. Auf einem hohen Niveau kann das Scheduling als das Einf\xfcgen von Verz\xf6gerungen in den Circuit verstanden werden, um die Leerlaufzeit auf den Qubits zwischen der Ausf\xfchrung von Anweisungen zu ber\xfccksichtigen."}),"\n"]}),"\n"]}),"\n",(0,s.jsxs)(n.p,{children:["Es gibt vier Optimierungsebenen von 0 bis 3, wobei h\xf6here Optimierungsebenen mehr Zeit und Rechenaufwand erfordern, aber m\xf6glicherweise einen besseren Circuit ergeben. Optimierungsebene 0 ist f\xfcr Ger\xe4tekalibrierungsexperimente vorgesehen und bildet als solche nur den Eingangs-Circuit auf die Einschr\xe4nkungen des Ziel-Backends ab, ohne Optimierungen durchzuf\xfchren. Optimierungsebene 3 investiert den meisten Aufwand zur Optimierung des Circuits. Da jedoch viele der Optimierungstechniken im Transpiler auf Heuristiken basieren, f\xfchrt mehr Rechenaufwand nicht immer zu einer Verbesserung der Qualit\xe4t des Ausgabe-Circuits. Wenn dies von weiterem Interesse ist, lies die ",(0,s.jsx)(n.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler",children:"Transpiler-Dokumentation"})," in der Qiskit-Dokumentation."]}),"\n",(0,s.jsx)(n.h4,{id:"error-suppression",children:"Error Suppression"}),"\n",(0,s.jsx)(n.p,{children:"Der erste Schritt zur Reduzierung von Fehlern in einem Circuit ist die Optimierung des Layouts, des Routings und die Minimierung der Gate-Anzahl, was wir bereits entweder mit dem Transpiler oder von Hand getan haben. Lass uns nun \xfcber einige ausgefeiltere Methoden der Error Suppression sprechen."}),"\n",(0,s.jsx)(n.p,{children:'Error Suppression bezeichnet eine Klasse von Techniken, die einen Circuit w\xe4hrend der Kompilierung transformieren, um Fehler zu minimieren. Sie unterscheidet sich von Error Mitigation, die wir sp\xe4ter im Abschnitt \u201eExecute" besprechen werden. Die beiden h\xe4ufigsten Formen der Error Suppression, die wir verwenden, sind Dynamical Decoupling und Pauli Twirling:'}),"\n",(0,s.jsxs)(n.ol,{children:["\n",(0,s.jsx)(n.li,{children:"Dynamical Decoupling wird verwendet, um einen Teil des durch Umweltrauschen eingef\xfchrten Fehlers, wenn ein Qubit im Leerlauf sitzt, effektiv aufzuheben. Durch das Anwenden einer Reihe von Gates zu bestimmten Zeitpunkten kann man daf\xfcr sorgen, dass sich das Rauschen, das in einem Teil der Leerlaufzeit akkumuliert, ungef\xe4hr mit dem Rauschen im anderen Teil aufhebt."}),"\n",(0,s.jsx)(n.li,{children:"Pauli Twirling ist eine Methode, bei der zuf\xe4llige Gates eingef\xfcgt werden, nicht um das Rauschen zu beseitigen, wie beim Dynamical Decoupling, sondern um es zu vereinfachen. Durch das Einf\xfcgen zuf\xe4lliger Gates wird verhindert, dass sich die Auswirkungen verschiedener Fehler so schnell aufbauen, und das Rauschen wird einfacher zu charakterisieren, da es nun stochastischen Charakter hat. Diese Methode bildet auch die Grundlage einer leistungsstarken Error-Mitigation-Technik, die wir im Folgenden besprechen werden."}),"\n"]}),"\n",(0,s.jsx)(n.h3,{id:"execute",children:"Ausf\xfchren (Execute)"}),"\n",(0,s.jsx)(n.p,{children:"Jetzt sind wir bereit, das Quantenprogramm auszuf\xfchren. Die Qiskit Runtime Primitives stellen eine Schnittstelle zur IBM-Quantum-Hardware bereit und abstrahieren auch Error Suppression und Mitigation vom Nutzer. Es stehen zwei Primitives zur Auswahl: der Sampler und der Estimator."}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.a,{href:"https://docs.quantum.ibm.com/api/qiskit-ibm-runtime/sampler",children:"Der Sampler von Qiskit Runtime"})," f\xfchrt den Circuit mehrfach auf einem Quantenger\xe4t aus, nimmt bei jedem Lauf Messungen vor und rekonstruiert die Wahrscheinlichkeitsverteilung aus den wiederhergestellten Bitstrings. Je mehr Durchl\xe4ufe (oder Shots) er durchf\xfchrt, desto genauer werden die Ergebnisse sein, aber das erfordert mehr Zeit und Quantenressourcen. Insbesondere berechnet er die Wahrscheinlichkeit, jeden m\xf6glichen Standardbasisstatus zu erhalten, indem er den vom Circuit vorbereiteten Zustand misst."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.a,{href:"https://docs.quantum.ibm.com/api/qiskit-ibm-runtime/estimator",children:"Der Estimator von Qiskit Runtime"})," verwendet einen komplexen algebraischen Prozess, um den Erwartungswert auf einem echten Quantenger\xe4t zu sch\xe4tzen, indem er die Observable in eine Kombination anderer Observablen mit bekannten Eigenbasen zerlegt."]}),"\n",(0,s.jsxs)(n.p,{children:["Der Execute-Schritt ist auch, wenn wir die ",(0,s.jsx)(n.em,{children:"Error Mitigation"}),"-Strategie ausw\xe4hlen k\xf6nnen. ",(0,s.jsx)(n.em,{children:"Error Mitigation"})," bezeichnet Techniken, die es Nutzern erm\xf6glichen, Circuit-Fehler zu reduzieren, indem das Ger\xe4terauschen modelliert wird, das zum Zeitpunkt der Ausf\xfchrung vorhanden war. Typischerweise f\xfchrt dies zu einem quantenseitigen Vorverarbeitungsaufwand f\xfcr das Modelltraining und einem klassischen Nachverarbeitungsaufwand, um Fehler in den Rohergebnissen mithilfe des generierten Modells zu mindern. Im Austausch f\xfcr diesen Overhead k\xf6nnen wir viel genauere Ergebnisse erhalten."]}),"\n",(0,s.jsx)(n.p,{children:"Es gibt mehrere Techniken, die wir f\xfcr Error Mitigation implementieren k\xf6nnen. Wir werden drei besprechen, in aufsteigender Reihenfolge der Fehlerresilienz, aber auch in aufsteigender Reihenfolge der Rechenkosten. Beachte jedoch, dass dies ein aktives Forschungsgebiet ist \u2013 daher werden wir wahrscheinlich weiterhin neue erfinden und alte verbessern."}),"\n",(0,s.jsx)(n.p,{children:"Bei Resilienz-Level 0 macht der Transpiler nichts mit deinem Circuit."}),"\n",(0,s.jsx)(n.p,{children:"Bei Level 1 f\xfchrt er eine Methode namens Twirled Readout Error eXtinction (T-REX) ein. T-REX verwendet Pauli Twirling, wie im Abschnitt \xfcber Error Suppression besprochen. Wie erw\xe4hnt, kann das Einf\xfcgen zuf\xe4lliger Gates in den Circuit selbst sehr kompliziertes, schwer zu modellierendes Rauschen stochastisch wirken lassen und es in der Nachverarbeitung viel einfacher machen, es zu ber\xfccksichtigen oder abzuziehen."}),"\n",(0,s.jsx)(n.p,{children:"Bei Resilienz-Level 2 wird Zero Noise Extrapolation (ZNE) hinzugef\xfcgt. Dies ist eine beliebte Technik, mit der wir in letzter Zeit viel Erfolg hatten. Die Idee hinter ZNE mag etwas \xfcberraschend sein \u2013 wir f\xfcgen tats\xe4chlich Rauschen zu dem hinzu, was bereits vorhanden ist! Aber das erm\xf6glicht es uns, in die entgegengesetzte Richtung zu extrapolieren und vorherzusagen, wie die Ergebnisse aussehen w\xfcrden, wenn es immer weniger Rauschen g\xe4be."}),"\n",(0,s.jsx)(n.p,{children:"Das Hinzuf\xfcgen von Rauschen kann auf verschiedene Arten erfolgen. Zum Beispiel k\xf6nnen wir die Gates verl\xe4ngern, damit sie l\xe4nger dauern und somit fehleranf\xe4lliger sind, oder mehr Gates ausf\xfchren, die letztendlich in einer Identit\xe4tsoperation resultieren, sodass sich der Circuit funktional nicht \xe4ndert, wir aber absichtlich mehr Rauschen abtasten. Du musst dies jedoch f\xfcr jeden Circuit und jeden Erwartungswert tun, den du verfolgen m\xf6chtest \u2013 daher kannst du sehen, wie es am Ende rechenintensiv werden kann."}),"\n",(0,s.jsx)(n.p,{children:"Eine spezifische Art von ZNE wird Probabilistic Error Amplification (PEA) genannt. Sobald wir ein Rauschmodell f\xfcr ein Gate gelernt haben, arbeitet PEA, indem Fehler aus diesem Rauschmodell abgetastet und absichtlich in den Circuit injiziert werden. Dies ist in Qiskit noch nicht verf\xfcgbar, wird aber sp\xe4ter in diesem Jahr erscheinen."}),"\n",(0,s.jsx)(n.p,{children:"Die letzte Form von Error Mitigation, die wir besprechen werden, ist Probabilistic Error Cancellation (PEC). Anstatt auf Level 3 zu sein, ist PEC eine spezielle F\xe4higkeit, die du manuell in Qiskit aktivieren musst, weil die erforderlichen Rechenressourcen im Vergleich zu den anderen Error-Mitigation-Techniken nicht sehr gut skalieren. Du beginnst damit, das Rauschen zu charakterisieren, das deinen Circuit beeinflusst \u2013 f\xfchre Rauschlernen- oder Rauschcharakterisierungs-Circuits f\xfcr jede eindeutige Schicht von Zwei-Qubit-Gates in deinem Circuit aus. Diese Ergebnisse erm\xf6glichen es dir, das Rauschen in Pauli-Operatoren zu beschreiben. Wenn du diese Rauschterme kennst, kannst du deine Circuits so modifizieren, dass sie effektiv die entgegengesetzten Pauli-Gates eingebaut haben, um diese Rauschkan\xe4le zu beseitigen. In gewisser Weise \xe4hnelt der Prozess der Funktionsweise von Noise-Cancelling-Kopfh\xf6rern. Diese Methode, das Rauschen r\xfcckg\xe4ngig zu machen, ist jedoch sehr kostspielig, mit einer Laufzeit, die schnell und exponentiell mit der Anzahl der Gates w\xe4chst, sodass es m\xf6glicherweise nicht die beste Wahl f\xfcr einen sehr gro\xdfen Circuit ist."}),"\n",(0,s.jsx)(n.h3,{id:"post-process",children:"Nachverarbeiten (Post-process)"}),"\n",(0,s.jsx)(n.p,{children:"Die Nachverarbeitungsphase ist der Ort, wo wir den Output unseres Quantencircuits visualisieren und analysieren. Es stehen dir eine Reihe von Qiskit-Tools zur Verf\xfcgung, wie z. B. die Visualisierungs- und Quantum-Info-Module. Wir werden diese hier nicht behandeln, aber wir werden diese Module in Aktion sehen, wenn wir in zuk\xfcnftigen Lektionen in einige Anwendungsbeispiele eintauchen."}),"\n",(0,s.jsx)(n.h2,{id:"conclusion",children:"Fazit"}),"\n",(0,s.jsx)(n.p,{children:'Hoffentlich hat dir diese Lektion einen schnellen \xdcberblick \xfcber die wichtigsten \xdcberlegungen und den Workflow gegeben, den wir verwenden, wenn wir eine Quantenberechnung im Utility-Ma\xdfstab durchf\xfchren m\xf6chten. Sie war vollgepackt mit Informationen, und vieles davon wird erst richtig sitzen, wenn wir einige tats\xe4chliche Beispiele sehen, wo diese theoretischen Konzepte in die Praxis umgesetzt werden. Das ist also, was der Rest des Kurses sein wird. Schlie\xdflich hei\xdft dieser Kurs nicht umsonst \u201eQuantum Computing in Practice"!'}),"\n",(0,s.jsx)(n.p,{children:"Beim n\xe4chsten Mal werden wir uns ein konkretes Beispiel ansehen, wie man den Qiskit-Patterns-Workflow verwendet, um einen Quantencircuit zu entwerfen und auszuf\xfchren, der das klassische Problem aus der Graphentheorie namens MaxCut l\xf6st."})]})}function c(e={}){const{wrapper:n}={...(0,t.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},77815(e,n,i){i.d(n,{A:()=>r});const r=i.p+"assets/images/circuitdepth-e2f15da4f6d03fbe250110f56450f666.avif"},54776(e,n,i){i.d(n,{A:()=>r});const r="data:image/avif;base64,"},28453(e,n,i){i.d(n,{R:()=>a,x:()=>u});var r=i(96540);const s={},t=r.createContext(s);function a(e){const n=r.useContext(t);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function u(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),r.createElement(t.Provider,{value:n},e.children)}}}]);